import sailpoint.object.Filter;
import sailpoint.object.Identity;
import sailpoint.object.Link;
import sailpoint.object.QueryOptions;
import sailpoint.object.TaskResult;
import sailpoint.api.Terminator;
import java.util.Date;
import java.text.SimpleDateFormat; 
import sailpoint.tools.Util;
import sailpoint.object.Filter.MatchMode;
import sailpoint.api.Terminator;

import org.apache.commons.logging.Log;
import org.apache.commons.logging.LogFactory;

boolean simulation = false;

StringBuilder resultStr = new StringBuilder();
int identitiesUpdated = 0;

Filter f1 = Filter.like("name", "AMITA\\", Filter.MatchMode.START);

QueryOptions qo = new QueryOptions();
qo.addFilter(f1);
 Terminator term = new Terminator (context);

//Filter typeFilter = Filter.or(f1, f2);
Iterator it = null;
try {
   it = context.search(Identity.class, qo,"name");
} catch (sailpoint.tools.GeneralException ge) {
   resultStr += ge.getMessage() + "\n";
   taskResult.addMessage(resultStr);
   return resultStr;
} 

while ((null != it) && (it.hasNext())) {

	String identityName = it.next()[0];
	
	if (Util.isNotNullOrEmpty(identityName)) {
		
		resultStr.append(identityName).append("\n");
		//identityName = "AMITA\\varma001";
	   Identity identity = context.getObjectByName(Identity.class, identityName);
	   
	   
	   identitiesUpdated++;
			if (simulation) {
				//do nothing
				
			} 
			else {
				
				context.removeObject(identity);
			
			
			}
	} 	
} //end while

resultStr.append("Identities Scanned:").append(identitiesUpdated);
context.commitTransaction();
  
	return resultStr.toString();
